#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

// Function to create a new process
void create_process() {
    pid_t pid = fork();
    if (pid == 0) {
        // Child process
        printf("Child process created with PID %d\n", getpid());
        execl("/bin/ls", "ls", NULL);
    } else {
        // Parent process
        printf("Parent process created with PID %d\n", getpid());
        wait(NULL);
        printf("Child process finished\n");
    }
}

// Function to manage memory
void manage_memory() {
    int* ptr = malloc(10 * sizeof(int));
    printf("Memory allocated at address %p\n", ptr);
    free(ptr);
    printf("Memory deallocated\n");
}

// Function to perform file I/O
void file_io() {
    FILE* file = fopen("example.txt", "w");
    if (file == NULL) {
        printf("Error opening file\n");
        return;
    }
    fprintf(file, "Hello, world!\n");
    fclose(file);
    printf("File written successfully\n");
}

// Function to perform networking
void networking() {
    int sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock == -1) {
        printf("Error creating socket\n");
        return;
    }
    struct sockaddr_in addr;
    addr.sin_family = AF_INET;
    addr.sin_port = htons(8080);
    inet_pton(AF_INET, "127.0.0.1", &addr.sin_addr);
    connect(sock, (struct sockaddr*)&addr, sizeof(addr));
    printf("Connected to server\n");
    close(sock);
    printf("Socket closed\n");
}

// Function to handle signals
void signal_handler(int sig) {
    printf("Received signal %d\n", sig);
}

// Function to perform IPC
void ipc() {
    int pipefd[2];
    pipe(pipefd);
    printf("Pipe created with file descriptors %d and %d\n", pipefd[0], pipefd[1]);
    close(pipefd[1]);
    char buffer[10];
    read(pipefd[0], buffer, 10);
    printf("Received message: %s\n", buffer);
    close(pipefd[0]);
    printf("Pipe closed\n");
}

int main() {
    create_process();
    manage_memory();
    file_io();
    networking();
    signal_handler(SIGINT);
    ipc();
    return 0;
}
```
